CREATE TABLE IF NOT EXISTS questionnaire_questions (
  id bigint PRIMARY KEY,
  question text NOT NULL,
  options jsonb DEFAULT '[]'::jsonb,
  min_responses integer,
  max_responses integer,
  multi_select boolean DEFAULT false,
  show_if jsonb,
  range_slider boolean DEFAULT false,
  min_value integer,
  max_value integer,
  default_range int[], 
  allow_custom boolean DEFAULT false,
  has_dropdown boolean DEFAULT false,
  ranked boolean DEFAULT false,
  default_answer text
);

TRUNCATE questionnaire_questions;

INSERT INTO questionnaire_questions (
  id, question, options, min_responses, max_responses, multi_select, show_if, 
