(1, 'I agree my data can be used for matchmaking & events and can be deleted on request.', '[{"value": "A", "label": "Yes"}, {"value": "B", "label": "No"}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
