(3, 'Pick your top 2 go-to vibes', '[{"value": "A", "label": "Outdoors"}, {"value": "B", "label": "Homebody"}, {"value": "C", "label": "Social"}, {"value": "D", "label": "Adventure"}]', 2, 2, true, '{"questionId": 2, "answer": "E"}', false, NULL, NULL, NULL, false, false, false, NULL),
(4, 'It''s Friday night after a long week — what sounds best?', '[{"value": "A", "label": "Going out with friends"}, {"value": "B", "label": "Staying in and relaxing"}, {"value": "C", "label": "Doing something creative or productive"}, {"value": "D", "label": "One-on-one time with someone special"}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
