(6, 'You notice something''s been bothering you in your relationship. What happens next?', '[{"value": "A", "label": "Bring it up right away"}, {"value": "B", "label": "Wait a bit, then ask gently"}, {"value": "C", "label": "Keep it to yourself"}, {"value": "D", "label": "Hope it resolves on its own"}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
(7, 'When I need support, I usually...', '[{"value": "A", "label": "Reach out right away - I hate dealing with things alone."}, {"value": "B", "label": "I try to handle it myself first, but will lean on a partner if i need to."}, {"value": "C", "label": "I prefer to deal with things alone - leaning on a partner feels uncomfortable."}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
(8, 'When my partner wants lots of closeness/time together, I usually...', '[{"value": "A", "label": "Feel overwhelmed and pull back"}, {"value": "B", "label": "Enjoy the closeness, but also appreciate breaks sometimes"}, {"value": "C", "label": "Love it - the more closeness the better"}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
(9, 'In a relationship, independence feels...', '[{"value": "A", "label": "More important than closeness - I need a lot of space."}, {"value": "B", "label": "Important, but I like balancing independence with intimacy."}, {"value": "C", "label": "Less important than closeness - I want to feel connected most of the time."}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
(10, 'When I sense my partner''s mood shifting, I...', '[{"value": "A", "label": "Notice right away and worry about what it means."}, {"value": "B", "label": "Notice and check in when the time feels right."}, {"value": "C", "label": "Often don''t notice until it''s really obvious"}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
(11, 'When I start dating someone new, I', '[{"value": "A", "label": "Get attached quickly and think about them a lot."}, {"value": "B", "label": "Take my time, but open up naturally as things build."}, {"value": "C", "label": "Stay cautious and hold back emotionally."}]', NULL, NULL, false, NULL, false, NULL, NULL, NULL, false, false, false, NULL),
